{
  "name": "Doc'scribe - Medical AI Scribe",
  "description": "A clinical documentation tool for Indian doctors that transforms patient-doctor conversations into SOAP notes, patient letters, and GP referrals using advanced AI.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export type DocType = 'SOAP' | 'PATIENT_LETTER' | 'GP_LETTER';

export interface Consultation {
  id: string;
  patientName: string;
  patientAge: string;
  transcript: string;
  selectedDocTypes: DocType[];
  documents: Partial<Record<DocType, string>>;
  status: 'IDLE' | 'RECORDING' | 'PROCESSING' | 'REVIEW';
  createdAt: Date;
}

export interface DocumentPrompt {
  type: DocType;
  title: string;
  description: string;
}

export interface BackendStructureInfo {
  endpoints: {
    path: string;
    method: string;
    description: string;
  }[];
  models: string[];
}

import { GoogleGenAI } from "@google/genai";
import { DocType, Consultation } from "../types";
import { SYSTEM_PROMPTS } from "../constants";

// The API key is provided via process.env.API_KEY
const genAI = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateDocument(
  type: DocType,
  consultation: Consultation
): Promise<string> {
  const model = "gemini-3-flash-preview";
  const systemInstruction = SYSTEM_PROMPTS[type];

  const prompt = `
    PATIENT INFO:
    Name: ${consultation.patientName}
    Age: ${consultation.patientAge}

    TRANSCRIPT OF CONSULTATION:
    ${consultation.transcript}

    INSTRUCTIONS:
    Generate the ${type} document based ONLY on the transcript above. 
    Ensure formatting is professional (Markdown).
    Do not include any placeholders like [Doctor Name]. Use "Consulting Physician" if needed.
  `;

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.2, // Low temperature for factual consistency in medical notes
      }
    });

    return response.text || "Failed to generate document.";
  } catch (error) {
    console.error(`Error generating ${type}:`, error);
    throw new Error(`AI generation failed for ${type}`);
  }
}

