import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2 } from 'lucide-react';

interface RecorderProps {
  onTranscriptComplete: (text: string) => void;
  isProcessing: boolean;
}

export const Recorder: React.FC<RecorderProps> = ({ onTranscriptComplete, isProcessing }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [timer, setTimer] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const intervalRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (intervalRef.current) window.clearInterval(intervalRef.current);
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.start();
      setIsRecording(true);
      setTimer(0);

      intervalRef.current = window.setInterval(() => {
        setTimer(prev => prev + 1);
      }, 1000);
    } catch (err) {
      console.error("Microphone access denied:", err);
      alert("Microphone access is required for recording.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      setIsRecording(false);
      if (intervalRef.current) window.clearInterval(intervalRef.current);

      // Simulating transcription for demo purposes
      // In a real app, you'd send the blob to a STT API like Gemini Flash Native Audio or Whisper
      const mockTranscript = "Patient reports persistent lower back pain for 3 weeks. Pain radiates to right leg. No trauma. Pain is 6/10. Dr. examined and found limited range of motion. Dr. advised MRI and rest. Prescribed Ibuprofen 400mg twice daily for 5 days.";
      onTranscriptComplete(mockTranscript);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col items-center gap-4 p-8 bg-blue-50 border-2 border-dashed border-blue-200 rounded-2xl">
      <div className="text-center space-y-2">
        <h3 className="font-semibold text-blue-900">Record Consultation</h3>
        <p className="text-sm text-blue-700">The session is transcribed in real-time. Minimum data shared.</p>
      </div>

      <div className="flex items-center gap-6">
        {!isRecording ? (
          <button
            onClick={startRecording}
            disabled={isProcessing}
            className="group relative flex items-center justify-center w-20 h-20 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition-all shadow-lg hover:shadow-blue-200 disabled:opacity-50"
          >
            <Mic className="w-8 h-8" />
            <span className="absolute -bottom-8 text-xs font-bold text-blue-600 uppercase tracking-widest">Start</span>
          </button>
        ) : (
          <button
            onClick={stopRecording}
            className="group relative flex items-center justify-center w-20 h-20 bg-red-600 text-white rounded-full hover:bg-red-700 animate-pulse transition-all shadow-lg"
          >
            <Square className="w-8 h-8" />
            <span className="absolute -bottom-8 text-xs font-bold text-red-600 uppercase tracking-widest">Stop</span>
          </button>
        )}
      </div>

      <div className="text-2xl font-mono text-slate-700 tabular-nums">
        {formatTime(timer)}
      </div>

      {isProcessing && (
        <div className="flex items-center gap-2 text-blue-600 font-medium">
          <Loader2 className="w-4 h-4 animate-spin" />
          Processing documentation...
        </div>
      )}
    </div>
  );
};

