    setConsultation({
      id: Math.random().toString(36).substr(2, 9),
      patientName: '',
      patientAge: '',
      transcript: '',
      selectedDocTypes: ['SOAP'],
      documents: {},
      status: 'IDLE',
      createdAt: new Date(),
    });
  };

  const handleDocTypeToggle = (type: DocType) => {
    setConsultation(prev => ({
      ...prev,
      selectedDocTypes: prev.selectedDocTypes.includes(type)
        ? prev.selectedDocTypes.filter(t => t !== type)
        : [...prev.selectedDocTypes, type]
    }));
  };

  const handleTranscriptComplete = async (transcript: string) => {
    setIsProcessing(true);
    setConsultation(prev => ({ ...prev, transcript, status: 'PROCESSING' }));

    const generatedDocs: Partial<Record<DocType, string>> = {};

    try {
      // Generate documents in parallel
      const promises = consultation.selectedDocTypes.map(async (type) => {
        const doc = await generateDocument(type, { ...consultation, transcript });
        generatedDocs[type] = doc;
      });

      await Promise.all(promises);

      setConsultation(prev => ({
        ...prev,
        documents: generatedDocs,
        status: 'REVIEW'
      }));
      setActiveReviewTab(consultation.selectedDocTypes[0]);
    } catch (error) {
      alert("Error generating documents. Please try again.");
      setConsultation(prev => ({ ...prev, status: 'IDLE' }));
    } finally {
      setIsProcessing(false);
    }
