import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2 } from 'lucide-react';

interface RecorderProps {
  onTranscriptComplete: (text: string) => void;
  isProcessing: boolean;
}

export const Recorder: React.FC<RecorderProps> = ({ onTranscriptComplete, isProcessing }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [timer, setTimer] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const intervalRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (intervalRef.current) window.clearInterval(intervalRef.current);
    };
  }, []);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.start();
      setIsRecording(true);
      setTimer(0);

      intervalRef.current = window.setInterval(() => {
        setTimer(prev => prev + 1);
      }, 1000);
    } catch (err) {
      console.error("Microphone access denied:", err);
      alert("Microphone access is required for recording.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      setIsRecording(false);
      if (intervalRef.current) window.clearInterval(intervalRef.current);

      // Developer Note: In production, the audio blob is sent to a Whisper/Gemini STT endpoint.
      // For this prototype, we simulate a successful capture.
      const simulatedTranscript = "The patient visited today regarding their ongoing IVF treatment. They expressed concerns about hormone injections causing mild nausea. Doctor confirmed the follicles are developing well on ultrasound and advised continuing current dosage. Next scan scheduled for Friday.";
      onTranscriptComplete(simulatedTranscript);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="p-6 bg-slate-50 rounded-xl border border-slate-200">
      <div className="flex items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          {!isRecording ? (
            <button
              onClick={startRecording}
              disabled={isProcessing}
              className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-full font-semibold hover:bg-blue-700 transition-all shadow-sm disabled:opacity-50"
            >
              <Mic className="w-5 h-5" />
              Start Recording
            </button>
          ) : (
            <button
              onClick={stopRecording}
              className="flex items-center gap-2 bg-red-600 text-white px-6 py-3 rounded-full font-semibold hover:bg-red-700 animate-pulse transition-all shadow-sm"
            >
              <Square className="w-5 h-5" />
              Stop Recording
            </button>
          )}

          <div className="text-xl font-mono text-slate-600 tabular-nums bg-white px-4 py-2 rounded-lg border border-slate-200">
            {formatTime(timer)}
          </div>
        </div>

        {isProcessing && (
          <div className="flex items-center gap-3 text-blue-600 font-medium text-sm animate-pulse">
            <Loader2 className="w-4 h-4 animate-spin" />
            Generating Clinical Documents...
          </div>
        )}
      </div>

      <p className="mt-4 text-xs text-slate-400">
        Clinical scribe active. Transcribing audio to text locally for review.
      </p>
    </div>
  );
};

function Mic({ className }: { className?: string }) { return <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 10v2a7 7 0 0 1-14 0v-2M12 18.5V23M8 23h8"/></svg>; }
function Square({ className }: { className?: string }) { return <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24"><rect strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" x="5" y="5" width="14" height="14" rx="1" ry="1"/></svg>; }
function Loader2({ className }: { className?: string }) { return <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/></svg>; }

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { Consultation, DocType } from './types';
import { DOC_PROMPTS } from './constants';
import { Recorder } from './components/Recorder';
import { generateDocument } from './services/geminiService';
import { FileText, User, Calendar, CheckCircle, ArrowLeft, Download, Loader2, ClipboardCheck } from 'lucide-react';

const App: React.FC = () => {
  const [consultation, setConsultation] = useState<Consultation>({
    id: Math.random().toString(36).substr(2, 9),
    patientName: '',
    patientAge: '',
    transcript: '',
    selectedDocTypes: ['SOAP'],
    documents: {},
    status: 'IDLE',
    createdAt: new Date(),
  });

  const [isProcessing, setIsProcessing] = useState(false);

  const startNewSession = () => {
    setConsultation({
      id: Math.random().toString(36).substr(2, 9),
      patientName: '',
      patientAge: '',
      transcript: '',
      selectedDocTypes: ['SOAP'],
      documents: {},
      status: 'IDLE',
      createdAt: new Date(),
    });
  };

  const handleDocTypeToggle = (type: DocType) => {
    setConsultation(prev => ({
      ...prev,
      selectedDocTypes: prev.selectedDocTypes.includes(type)
        ? prev.selectedDocTypes.filter(t => t !== type)
        : [...prev.selectedDocTypes, type]
    }));
  };

  const handleTranscriptComplete = async (transcript: string) => {
    if (!consultation.patientName || !consultation.patientAge) {
      alert("Please enter patient name and age first.");
      return;
    }

    setIsProcessing(true);
    setConsultation(prev => ({ ...prev, transcript, status: 'PROCESSING' }));

    const generatedDocs: Partial<Record<DocType, string>> = {};

    try {
      const promises = consultation.selectedDocTypes.map(async (type) => {
        const doc = await generateDocument(type, { ...consultation, transcript });
        generatedDocs[type] = doc;
      });

      await Promise.all(promises);

      setConsultation(prev => ({
        ...prev,
        documents: generatedDocs,
        status: 'REVIEW'
      }));
    } catch (error) {
      alert("Error generating documents. Using strict grounding filters.");
      setConsultation(prev => ({ ...prev, status: 'IDLE' }));
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadDocument = (type: DocType) => {
    const content = consultation.documents[type];
    if (!content) return;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `DocScribe_${consultation.patientName.replace(/\s+/g, '_')}_${type}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <Layout>
      <div className="max-w-3xl mx-auto">
        {consultation.status !== 'REVIEW' ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8 space-y-8">
              <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                  <FileText className="w-5 h-5 text-blue-600" />
                  Patient Consultation
                </h2>
                <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">Session ID: {consultation.id}</span>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Patient Name</label>
                  <input
                    type="text"
                    value={consultation.patientName}
                    onChange={(e) => setConsultation(prev => ({ ...prev, patientName: e.target.value }))}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                    placeholder="e.g. Anjali Gupta"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Age</label>
                  <input
                    type="number"
                    value={consultation.patientAge}
                    onChange={(e) => setConsultation(prev => ({ ...prev, patientAge: e.target.value }))}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                    placeholder="e.g. 29"
                  />
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-xs font-bold text-slate-500 uppercase">Documents to Generate</label>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                  {DOC_PROMPTS.map((doc) => (
                    <button
                      key={doc.type}
                      onClick={() => handleDocTypeToggle(doc.type)}
                      className={`p-4 text-left border rounded-xl transition-all ${
                        consultation.selectedDocTypes.includes(doc.type)
                          ? 'border-blue-500 bg-blue-50/50'
                          : 'border-slate-200 bg-white hover:border-slate-300'
                      }`}
                    >
                      <div className="flex justify-between items-start mb-1">
                        <span className={`p-1 rounded-md ${consultation.selectedDocTypes.includes(doc.type) ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                           <CheckCircle className="w-3 h-3" />
                        </span>
                      </div>
                      <div className="font-semibold text-slate-800 text-sm">{doc.title}</div>
                      <div className="text-[10px] text-slate-400 mt-0.5 leading-tight">{doc.description}</div>
                    </button>
                  ))}
                </div>
              </div>

              <Recorder onTranscriptComplete={handleTranscriptComplete} isProcessing={isProcessing} />
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in zoom-in-95 duration-300">
            <div className="flex items-center justify-between">
              <button 
                onClick={startNewSession}
                className="flex items-center gap-2 text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors"
              >
                <ArrowLeft className="w-4 h-4" /> New Consultation
              </button>
              <div className="text-right">
                <h3 className="font-bold text-slate-800">{consultation.patientName}</h3>
                <p className="text-xs text-slate-500">Age: {consultation.patientAge} • Consultation Reviewed</p>
              </div>
            </div>

            <div className="space-y-6">
              {consultation.selectedDocTypes.map((type) => (
                <div key={type} className="bg-white border border-slate-200 rounded-xl shadow-sm overflow-hidden">
                  <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <ClipboardCheck className="w-4 h-4 text-blue-600" />
                      <h4 className="font-bold text-slate-700">{DOC_PROMPTS.find(p => p.type === type)?.title}</h4>
                    </div>
                    <button 
                      onClick={() => downloadDocument(type)}
                      className="flex items-center gap-1.5 text-xs font-bold text-blue-600 hover:text-blue-700 bg-blue-50 hover:bg-blue-100 px-3 py-1.5 rounded-lg transition-colors"
                    >
                      <Download className="w-3 h-3" /> Download .txt
                    </button>
                  </div>
                  <div className="p-8">
                    <div className="prose prose-slate max-w-none text-slate-700 text-sm leading-relaxed whitespace-pre-wrap font-sans">
                      {consultation.documents[type] || "Generating content..."}
                    </div>
                  </div>
                </div>
