    setConsultation(prev => ({ ...prev, transcript, status: 'PROCESSING' }));

    const generatedDocs: Partial<Record<DocType, string>> = {};

    try {
      const promises = consultation.selectedDocTypes.map(async (type) => {
        const doc = await generateDocument(type, { ...consultation, transcript });
        generatedDocs[type] = doc;
      });

      await Promise.all(promises);

      setConsultation(prev => ({
        ...prev,
        documents: generatedDocs,
        status: 'REVIEW'
      }));
    } catch (error) {
      alert("Error generating documents. Please check your transcript.");
      setConsultation(prev => ({ ...prev, status: 'IDLE' }));
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadDocument = (type: DocType) => {
    const content = consultation.documents[type];
    if (!content) return;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `MedNote_${consultation.patientName.replace(/\s+/g, '_')}_${type}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-blue-600 p-8 text-center">
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg rotate-3">
              <Activity className="w-10 h-10 text-blue-600" />
            </div>
            <h1 className="text-3xl font-bold text-white">MedNote AI</h1>
            <p className="text-blue-100 mt-2 text-sm">Professional Medical Scribe Assistant</p>
          </div>
          <div className="p-8 space-y-6">
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase">Provider ID</label>
                <input type="text" value="DR_SHARMA_772" readOnly className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-mono text-sm" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase">Access Code</label>
                <input type="password" value="••••••••" readOnly className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-mono" />
              </div>
            </div>
            <button 
              onClick={() => setIsAuthenticated(true)}
              className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-all shadow-md active:scale-95"
            >
              <LogIn className="w-5 h-5" />
              Secure Login
            </button>
            <div className="flex items-center justify-center gap-2 text-[10px] text-slate-400 font-bold uppercase tracking-widest pt-2">
              <ShieldCheck className="w-3 h-3" />
              HIPAA Compliant & Secure
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout>
      <div className="max-w-3xl mx-auto">
        {consultation.status !== 'REVIEW' ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 space-y-8">
              <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                  <FileText className="w-5 h-5 text-blue-600" />
                  Clinical Intake
                </h2>
                <div className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-[10px] font-bold uppercase tracking-wider border border-blue-100">
                  Patient No: {consultation.id}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Patient Name</label>
                  <input
                    type="text"
                    value={consultation.patientName}
                    onChange={(e) => setConsultation(prev => ({ ...prev, patientName: e.target.value }))}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all shadow-sm"
                    placeholder="e.g. Ramesh Kumar"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Age</label>
                  <input
                    type="number"
                    value={consultation.patientAge}
                    onChange={(e) => setConsultation(prev => ({ ...prev, patientAge: e.target.value }))}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all shadow-sm"
                    placeholder="e.g. 45"
                  />
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-xs font-bold text-slate-500 uppercase">Required Documentation</label>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                  {DOC_PROMPTS.map((doc) => (
                    <button
                      key={doc.type}
                      onClick={() => handleDocTypeToggle(doc.type)}
                      className={`p-4 text-left border-2 rounded-xl transition-all ${
                        consultation.selectedDocTypes.includes(doc.type)
                          ? 'border-blue-500 bg-blue-50/30'
                          : 'border-slate-100 bg-white hover:border-slate-200'
                      }`}
                    >
                      <div className="flex justify-between items-start mb-2">
                        <span className={`p-1.5 rounded-lg ${consultation.selectedDocTypes.includes(doc.type) ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                           <CheckCircle className="w-3.5 h-3.5" />
                        </span>
                      </div>
                      <div className="font-bold text-slate-800 text-sm leading-tight">{doc.title}</div>
                      <div className="text-[10px] text-slate-400 mt-1 leading-tight">{doc.description}</div>
                    </button>
                  ))}
                </div>
              </div>

              <Recorder onTranscriptComplete={handleTranscriptComplete} isProcessing={isProcessing} />

              {isProcessing && (
                <div className="flex flex-col items-center gap-4 py-8 bg-slate-50 rounded-2xl border border-slate-200 animate-in fade-in duration-700">
                  <div className="relative">
                    <Loader2 className="w-12 h-12 text-blue-600 animate-spin" />
                    <div className="absolute inset-0 flex items-center justify-center">
                      <Activity className="w-4 h-4 text-blue-400 animate-pulse" />
                    </div>
                  </div>
                  <div className="text-center space-y-1">
                    <p className="text-blue-700 font-bold text-sm transition-all duration-500">{steps[processingStep]}</p>
                    <p className="text-[10px] text-slate-400 uppercase tracking-widest">Medical LLM is analyzing transcript</p>
                  </div>
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in zoom-in-95 duration-500">
            <div className="flex items-center justify-between">
              <button 
                onClick={startNewSession}
                className="flex items-center gap-2 text-slate-500 hover:text-slate-900 text-sm font-bold transition-colors group"
              >
                <ArrowLeft className="w-4 h-4 transition-transform group-hover:-translate-x-1" /> New Session
              </button>
              <div className="text-right">
                <h3 className="font-bold text-slate-800 text-lg">{consultation.patientName}</h3>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Reviewed & Validated</p>
              </div>
            </div>

            <div className="space-y-6">
              {consultation.selectedDocTypes.map((type) => (
                <div key={type} className="bg-white border border-slate-200 rounded-2xl shadow-md overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-lg bg-blue-100 flex items-center justify-center">
                        <ClipboardCheck className="w-4 h-4 text-blue-600" />
                      </div>
                      <h4 className="font-bold text-slate-700">{DOC_PROMPTS.find(p => p.type === type)?.title}</h4>
                    </div>
                    <button 
                      onClick={() => downloadDocument(type)}
                      className="flex items-center gap-1.5 text-xs font-bold text-blue-600 hover:text-white hover:bg-blue-600 border border-blue-600 px-4 py-2 rounded-xl transition-all shadow-sm active:scale-95"
                    >
                      <Download className="w-3.5 h-3.5" /> Download Summary
                    </button>
                  </div>
                  <div className="p-8">
                    {!consultation.documents[type] ? (
                      <div className="space-y-4">
                        <div className="h-4 w-3/4 shimmer rounded-lg"></div>
                        <div className="h-4 w-full shimmer rounded-lg"></div>
                        <div className="h-4 w-5/6 shimmer rounded-lg"></div>
                        <div className="h-4 w-1/2 shimmer rounded-lg"></div>
                      </div>
                    ) : (
                      <div className="prose prose-slate max-w-none text-slate-700 text-sm leading-relaxed whitespace-pre-wrap font-sans">
                        {consultation.documents[type]}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>

            <div className="bg-emerald-50 border border-emerald-100 rounded-2xl p-8 text-center shadow-sm">
              <div className="w-12 h-12 bg-emerald-500 rounded-full flex items-center justify-center mx-auto mb-3 shadow-md">
                <CheckCircle className="text-white w-6 h-6" />
              </div>
              <h4 className="text-emerald-900 font-bold">Session Successfully Documented</h4>
              <p className="text-xs text-emerald-700/70 mt-1">All requested medical records have been generated and reviewed.</p>
              <button 
                onClick={startNewSession}
                className="mt-6 bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold text-sm hover:bg-emerald-700 transition-all shadow-md active:scale-95"
              >
                Document Next Consultation
              </button>
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

