import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Consultation, DocType, Provider } from './types';
import { DOC_PROMPTS } from './constants';
import { Recorder } from './components/Recorder';
import { generateDocument } from './services/geminiService';
import { FileText, User, Calendar, CheckCircle, ArrowLeft, Download, Loader2, ClipboardCheck, LogIn, Activity, ShieldCheck, Building2, UserCircle } from 'lucide-react';

const App: React.FC = () => {
  const [provider, setProvider] = useState<Provider | null>(() => {
    const saved = localStorage.getItem('mednote_provider');
    return saved ? JSON.parse(saved) : null;
  });

  const [loginForm, setLoginForm] = useState({
    name: 'Dr. Jane Smith',
    practice: 'Westside Medical Center',
    code: '7721'
  });

  const [consultation, setConsultation] = useState<Consultation>({
    id: Math.random().toString(36).substr(2, 9),
    patientName: '',
    patientAge: '',
    transcript: '',
    selectedDocTypes: ['SOAP'],
    documents: {},
    status: 'IDLE',
    createdAt: new Date(),
  });

  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState(0);

  const steps = [
    "Transcribing consultation...",
    "Analyzing clinical data...",
    "Generating medical record...",
    "Generating patient letter...",
    "Finalizing documentation..."
  ];

  useEffect(() => {
    let interval: number;
    if (isProcessing) {
      interval = window.setInterval(() => {
        setProcessingStep((prev) => (prev < steps.length - 1 ? prev + 1 : prev));
      }, 2500);
    } else {
      setProcessingStep(0);
    }
    return () => window.clearInterval(interval);
  }, [isProcessing]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!loginForm.name || !loginForm.practice) return;

    const newProvider: Provider = {
      name: loginForm.name,
      practice: loginForm.practice,
      id: `PN-${Math.floor(1000 + Math.random() * 9000)}`
    };

    setProvider(newProvider);
    localStorage.setItem('mednote_provider', JSON.stringify(newProvider));
  };

  const handleLogout = () => {
    setProvider(null);
    localStorage.removeItem('mednote_provider');
  };

  const startNewSession = () => {
    setConsultation({
      id: Math.random().toString(36).substr(2, 9),
      patientName: '',
      patientAge: '',
      transcript: '',
      selectedDocTypes: ['SOAP'],
      documents: {},
      status: 'IDLE',
      createdAt: new Date(),
    });
  };

  const handleDocTypeToggle = (type: DocType) => {
    setConsultation(prev => ({
      ...prev,
      selectedDocTypes: prev.selectedDocTypes.includes(type)
        ? prev.selectedDocTypes.filter(t => t !== type)
        : [...prev.selectedDocTypes, type]
    }));
  };

  const handleTranscriptComplete = async (transcript: string) => {
    if (!consultation.patientName || !consultation.patientAge) {
      alert("Please enter patient name and age first.");
      return;
    }

    setIsProcessing(true);
    setConsultation(prev => ({ ...prev, transcript, status: 'PROCESSING' }));

    const generatedDocs: Partial<Record<DocType, string>> = {};

    try {
      const promises = consultation.selectedDocTypes.map(async (type) => {
        const doc = await generateDocument(type, { ...consultation, transcript });
        generatedDocs[type] = doc;
      });

      await Promise.all(promises);

      setConsultation(prev => ({
        ...prev,
        documents: generatedDocs,
        status: 'REVIEW'
      }));
    } catch (error) {
      alert("Error generating documents. Please check your transcript.");
      setConsultation(prev => ({ ...prev, status: 'IDLE' }));
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadDocument = (type: DocType) => {
    const content = consultation.documents[type];
    if (!content) return;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `MedNote_${consultation.patientName.replace(/\s+/g, '_')}_${type}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  if (!provider) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-blue-600 p-10 text-center relative overflow-hidden">
            <Activity className="absolute -right-4 -top-4 w-32 h-32 text-blue-500/20 rotate-12" />
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg relative z-10">
              <Activity className="w-10 h-10 text-blue-600" />
            </div>
            <h1 className="text-3xl font-bold text-white relative z-10">MedNote AI</h1>
            <p className="text-blue-100 mt-2 text-sm relative z-10">Secure Clinical Scribe Access</p>
          </div>

          <form onSubmit={handleLogin} className="p-8 space-y-6">
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                  <UserCircle className="w-3 h-3" /> Full Name
                </label>
                <input 
                  type="text" 
                  required
                  placeholder="e.g. Dr. Jane Smith"
                  value={loginForm.name}
                  onChange={(e) => setLoginForm({...loginForm, name: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-sm font-medium" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                  <Building2 className="w-3 h-3" /> Practice Name
                </label>
                <input 
                  type="text" 
                  required
                  placeholder="e.g. City General Hospital"
                  value={loginForm.practice}
                  onChange={(e) => setLoginForm({...loginForm, practice: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all text-sm font-medium" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Access Key</label>
                <input 
                  type="password" 
                  required
                  placeholder="••••••••"
                  value={loginForm.code}
                  onChange={(e) => setLoginForm({...loginForm, code: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all font-mono" 
                />
              </div>
            </div>

            <button 
              type="submit"
              className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-all shadow-md active:scale-95 group"
            >
              <LogIn className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
              Secure Login
            </button>

            <div className="flex items-center justify-center gap-2 text-[10px] text-slate-400 font-bold uppercase tracking-widest pt-2">
              <ShieldCheck className="w-3.5 h-3.5 text-emerald-500" />
              Encrypted Session Active
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <Layout provider={provider} onLogout={handleLogout}>
      <div className="max-w-3xl mx-auto">
        {consultation.status !== 'REVIEW' ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 space-y-8">
              <div className="flex items-center justify-between border-b border-slate-100 pb-6">
                <div>
                  <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                    <FileText className="w-5 h-5 text-blue-600" />
                    Patient Consultation
                  </h2>
                  <p className="text-xs text-slate-500 mt-1">Provider: {provider.name}</p>
                </div>
                <div className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-[10px] font-bold uppercase tracking-wider border border-blue-100">
                  ID: {consultation.id}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Patient Name</label>
                  <input
                    type="text"
                    value={consultation.patientName}
                    onChange={(e) => setConsultation(prev => ({ ...prev, patientName: e.target.value }))}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all shadow-sm"
                    placeholder="e.g. Ramesh Kumar"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Age</label>
                  <input
                    type="number"
                    value={consultation.patientAge}
                    onChange={(e) => setConsultation(prev => ({ ...prev, patientAge: e.target.value }))}
                    className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all shadow-sm"
                    placeholder="e.g. 45"
                  />
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Select Output Modules</label>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                  {DOC_PROMPTS.map((doc) => (
                    <button
                      key={doc.type}
                      onClick={() => handleDocTypeToggle(doc.type)}
                      className={`p-4 text-left border-2 rounded-xl transition-all ${
                        consultation.selectedDocTypes.includes(doc.type)
                          ? 'border-blue-500 bg-blue-50/30'
                          : 'border-slate-100 bg-white hover:border-slate-200'
                      }`}
                    >
