import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Consultation, DocType, Provider } from './types';
import { DOC_PROMPTS } from './constants';
import { Recorder } from './components/Recorder';
import { generateDocument } from './services/geminiService';
import { FileText, User, Calendar, CheckCircle, ArrowLeft, Download, Loader2, ClipboardCheck, LogIn, Activity, ShieldCheck, Building2, UserCircle, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [provider, setProvider] = useState<Provider | null>(() => {
    const saved = localStorage.getItem('mednote_provider');
    return saved ? JSON.parse(saved) : null;
  });

  const [loginForm, setLoginForm] = useState({
    name: 'Dr. Jane Smith',
    practice: 'Westside Medical Center',
    code: '7721'
  });

  const [consultation, setConsultation] = useState<Consultation>({
    id: Math.random().toString(36).substr(2, 9),
    patientName: '',
    patientAge: '',
    transcript: '',
    selectedDocTypes: ['SOAP'],
    documents: {},
    status: 'IDLE',
    createdAt: new Date(),
  });

  const [isProcessing, setIsProcessing] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!loginForm.name || !loginForm.practice) return;

    const newProvider: Provider = {
      name: loginForm.name,
      practice: loginForm.practice,
      id: `PN-${Math.floor(1000 + Math.random() * 9000)}`
    };

    setProvider(newProvider);
    localStorage.setItem('mednote_provider', JSON.stringify(newProvider));
  };

  const handleLogout = () => {
    setProvider(null);
    localStorage.removeItem('mednote_provider');
  };

  const startNewSession = () => {
    setConsultation({
      id: Math.random().toString(36).substr(2, 9),
      patientName: '',
      patientAge: '',
      transcript: '',
      selectedDocTypes: ['SOAP'],
      documents: {},
      status: 'IDLE',
      createdAt: new Date(),
    });
    setIsProcessing(false);
  };

  const handleDocTypeToggle = (type: DocType) => {
    setConsultation(prev => ({
      ...prev,
      selectedDocTypes: prev.selectedDocTypes.includes(type)
        ? prev.selectedDocTypes.filter(t => t !== type)
        : [...prev.selectedDocTypes, type]
    }));
  };

  const handleTranscriptComplete = (transcript: string) => {
    if (!consultation.patientName || !consultation.patientAge) {
      alert("Please enter patient name and age first.");
      return;
    }

    // MICRO-SECOND HACK: Transition to Review status IMMEDIATELY
    setIsProcessing(true);
    setConsultation(prev => ({ 
      ...prev, 
      transcript, 
      status: 'REVIEW',
      documents: {} // Reset for new generation
    }));

    // Trigger generations in parallel but update state as each one finishes
    consultation.selectedDocTypes.forEach(async (type) => {
      try {
        const docContent = await generateDocument(type, { ...consultation, transcript });

        setConsultation(prev => ({
          ...prev,
          documents: {
            ...prev.documents,
            [type]: docContent
