    // Regex to find <term def="...">Word</term>
    const termRegex = /<term def="([^"]+)">([^<]+)<\/term>/g;
    const parts = [];
    let lastIndex = 0;
    let match;

    while ((match = termRegex.exec(content)) !== null) {
      // Add text before the match
