                      </div>
                    </div>
                    {consultation.documents[type] && (
                      <button onClick={() => downloadDocument(type)} className="flex items-center gap-3 text-sm font-black text-white bg-slate-900 px-8 py-4 rounded-[1.5rem] hover:bg-black shadow-2xl active:scale-95 transition-all">
                        <Download className="w-5 h-5" /> EXPORT DOC
                      </button>
                    )}
                  </div>
                  <div className="p-12 bg-white relative">
                    {!consultation.documents[type] ? (
                      <div className="space-y-8 py-4">
                        <div className="h-6 w-3/4 shimmer rounded-full"></div>
                        <div className="h-6 w-full shimmer rounded-full"></div>
                        <div className="h-6 w-5/6 shimmer rounded-full"></div>
                        <div className="h-6 w-2/3 shimmer rounded-full"></div>
                      </div>
                    ) : (
                      <div 
                        contentEditable 
                        onBlur={(e) => updateDocContent(type, e.currentTarget.innerHTML)}
                        suppressContentEditableWarning={true}
                        className="prose prose-slate max-w-none text-slate-700 text-xl leading-[1.8] font-medium outline-none min-h-[300px] focus:bg-slate-50/30 transition-all rounded-[2rem] p-4"
                      >
                        {parseMedicalTerms(consultation.documents[type] || "")}
                        {isProcessing && <span className="inline-block w-3 h-6 bg-blue-500 animate-pulse ml-2 align-middle rounded-sm" />}
                      </div>
                    )}
                  </div>
                  <div className="bg-slate-50 px-12 py-6 border-t border-slate-100 flex items-center justify-between">
                     <div className="flex items-center gap-3">
                        <Info className="w-5 h-5 text-blue-500" />
                        <span className="text-[11px] text-slate-400 font-black uppercase tracking-[0.2em]">Validated by MedNote AI Engine</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <ShieldCheck className="w-4 h-4 text-emerald-500" />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">HIPAA Compliant Processing</span>
                     </div>
                  </div>
                </div>
              ))}
            </div>

            {allDocsReady && !isProcessing && (
              <div className="fixed bottom-12 left-1/2 -translate-x-1/2 w-full max-w-xl px-6 animate-in slide-in-from-bottom-20 duration-1000">
                <button onClick={startNewSession} className="w-full bg-blue-600 text-white py-8 rounded-[2.5rem] font-black text-2xl shadow-[0_30px_60px_rgba(37,99,235,0.4)] hover:bg-blue-700 transition-all active:scale-95 flex items-center justify-center gap-5 border-8 border-white ring-2 ring-blue-600/10">
                  <CheckCircle className="w-9 h-9 text-white" /> COMPLETE WORKFLOW
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </Layout>
  );
};

